}

.page,#mw-content-text,.main-container,.page__main{
background:rgba(0, 0, 0,1)!important;
color:#ffffff!important;
}

.page{
border:2px solid rgba(255, 255, 255,.6);
border-radius:6px;
padding:16px;
margin-top:12px;

box-shadow:
0 0 18px rgba(255, 255, 255,.14),
0 0 42px rgba(255, 255, 255,.05);

line-height:1.6;
}

.shaky-text {
    display: inline-block;
    animation: shake 0.4s infinite;
}

@keyframes shake {
    0%   { transform: translate(1px, 1px) rotate(0deg); }
    10%  { transform: translate(-1px, -2px) rotate(-1deg); }
    20%  { transform: translate(-3px, 0px) rotate(1deg); }
    30%  { transform: translate(3px, 2px) rotate(0deg); }
    40%  { transform: translate(1px, -1px) rotate(1deg); }
    50%  { transform: translate(-1px, 2px) rotate(-1deg); }
    60%  { transform: translate(-3px, 1px) rotate(0deg); }
    70%  { transform: translate(3px, 2px) rotate(-1deg); }
    80%  { transform: translate(-1px, -1px) rotate(1deg); }
    90%  { transform: translate(1px, 2px) rotate(0deg); }
    100% { transform: translate(1px, -2px) rotate(-1deg); }
}

.more-shaky-text {
    display: inline-block;
    animation: shake 0.3s infinite ease-in-out;
}

@keyframes shake {
    0%   { transform: translate(0.5px, 0.5px) rotate(0deg); }
    10%  { transform: translate(-0.5px, -0.8px) rotate(-0.1deg); }
    20%  { transform: translate(-1px, 0px) rotate(0.1deg); }
    30%  { transform: translate(1px, 0.8px) rotate(0deg); }
    40%  { transform: translate(0.5px, -0.5px) rotate(0.1deg); }
    50%  { transform: translate(-0.5px, 0.8px) rotate(-0.1deg); }
    60%  { transform: translate(-1px, 0.5px) rotate(0deg); }
    70%  { transform: translate(1px, 0.8px) rotate(-0.1deg); }
    80%  { transform: translate(-0.5px, -0.5px) rotate(0.1deg); }
    90%  { transform: translate(0.5px, 0.8px) rotate(0deg); }
    100% { transform: translate(0.5px, -0.5px) rotate(-0.1deg); }
}

